/// <summary>
/// Journal header is created by using this new method
/// </summary>
/// <returns>JournalId.</returns>
public JournalId createJournalHeader()
{
    LedgerJournalTable  ledgerJournalTable;

    ledgerJournalTable.clear();
    ledgerJournalTable.JournalName          = SalesParameters::find().ETGJournalName;
    ledgerJournalTable.initfromLedgerJournalName();
    ledgerJournalTable.journalNum           = JournalTableData::newTable(ledgerJournalTable).nextJournalId();
    ledgerJournalTable.JournalType          = LedgerJournalType::CustPayment;
    ledgerJournalTable.insert();

    return ledgerJournalTable.JournalNum;
}

/// <summary>
/// Creates Journal lines by using this new method.
/// </summary>
/// <param name = "custInvoiceJour">CustInvoiceJour</param>
/// <param name = "custInvoiceTrans">CustInvoiceTrans</param>
/// <param name = "journalId">JournalId</param>
public void createJournalLine(CustInvoiceJour custInvoiceJour, CustInvoiceTrans custInvoiceTrans, JournalId journalId)
{
    LedgerJournalTrans  ledgerJournalTrans;
    NumberSeq           numberSeq;

    numberSeq                               = NumberSeq::newGetVoucherFromId(LedgerJournalName::find(SalesParameters::find().ETGJournalName).NumberSequenceTable);
    LedgerjournalTrans.Voucher              = numberSeq.voucher();
    ledgerJournalTrans.initValue();
    ledgerJournalTrans.JournalNum           = journalId;
    ledgerJournalTrans.TransDate            = DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone());
    ledgerJournalTrans.AccountType          = LedgerJournalACType::Cust;
    ledgerJournalTrans.Txt                  = custInvoiceJour.InvoicingName;
    ledgerJournalTrans.OffsetAccountType    = LedgerJournalACType::Bank;
    ledgerJournalTrans.CurrencyCode         = custInvoiceTrans.CurrencyCode;
    ledgerJournalTrans.TransactionType      = LedgerTransType::Payment;
    ledgerJournalTrans.parmAccount(custInvoiceJour.InvoiceAccount, ledgerJournalTrans.AccountType);
    ledgerJournalTrans.AmountCurCredit      = custInvoiceTrans.ETGDepositAmount;
    ledgerJournalTrans.MarkedInvoice        = custInvoiceJour.InvoiceId;
    ledgerJournalTrans.insert();

    custInvoiceTrans.selectForUpdate(true);
    custInvoiceTrans.ETGCylinderTrackPaymJourCreated = NoYes::Yes;
    custInvoiceTrans.doUpdate();
}
